  ('generalpolice-8b7f1efc-moex-00246', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於行政訴訟法上暫時權利保護之敘述，下列何者正確？', '["為保全公法上金錢給付之執行，得聲請假處分", "一旦提起行政訴訟後，即停止原處分或決定之執行", "針對得聲請停止執行之處分或決定，即不得聲請假處分", "行政訴訟繫屬中，行政法院不得依職權裁定停止執行，一律必須待當事人之聲請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00247', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-113-3082b5f1', 'sub-generalpolice-8b7f1efc-07', NULL, 'single_choice', '關於國家賠償責任之成立要件，下列敘述何者錯誤？', '["凡公務員執行職務時侵害人民自由或權利，不問公務員是否有故意或過失，由國家承擔賠償 責任", "執行職務者，為受託行使公權力之民間團體或個人，即視為委託機關之公務員，由國家承擔賠 償責任", "公共設施之設置或管理有欠缺，致損害人民身體或財產權利，不問設置人或管理人有故意或過 失，由國家承擔賠償責任", "公共設施委託民間團體或個人管理，因管理欠缺致人民身體或財產權利受損，由國家承擔賠償 責任"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:34+00:00", "source_pdf_sha1": "e0a865ce9ca1", "answer_pdf_sha1": "4d7aa157a30b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "301", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
